import todoList from "./todoList.js";

export default function todoListController () {
    let todoLists = {};

    const getList = () => todoLists;

    const getLabels = () => Object.keys(todoLists)

    const addList = (name) => {
        const newTodoList = todoList(name);
        if (!Object.keys(todoLists).includes(name)) {
            todoLists[name] = newTodoList
        }
    }

    const deleteList = (name) => {
        Reflect.deleteProperty(todoLists, name)
    }

    const save = () => {
        const todos = {};
        for (const key in todoLists) {
            todos[key] = todoLists[key].getList();
        }
        const stringifiedTodos= JSON.stringify(todos)
        localStorage.setItem("todos", stringifiedTodos)
    }

    const load = () => {
        const stringifiedTodos = localStorage.getItem("todos");
        const todos = JSON.parse(stringifiedTodos)
        
        todoLists = {};
        for (const key in todos) {
            addList(key);
            if (key != "All Todos") {
                getList()[key].replaceList(todos[key])
            } else {
                getList()["All Todos"].concatList(todos[key])
            }
        }
        addList("All Todos")
    }

    return {getList, getLabels, addList, deleteList, save, load}
}
